func getOrderDetails(w http.ResponseWriter, r *http.Request) {
	// Extract the order ID from the URL path
	orderID := r.URL.Path[len("/orders/"):]

	// Query the database for the order details
	db := r.Context().Value("database").(*sql.DB)
	row := db.QueryRow(`SELECT * FROM orders WHERE id = ?`, orderID)

	var order Order
	err := row.Scan(&order.ID, &order.CustomerName, &order.Status)
	if err != nil {
		fmt.Fprintf(w, "Error retrieving order details: %s", err)
	} else {
		// Return the order details as JSON
		json.NewEncoder(w).Encode(order)
	}
}